package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.PatientServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Set;
@WebServlet("/admin/patients")public class PatientListServlet extends HttpServlet{private final PatientService service;public PatientListServlet(){this(new PatientServiceImpl());}public PatientListServlet(PatientService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PageRequest p=new PageRequest(num(q.getParameter("page"),1),num(q.getParameter("size"),10),q.getParameter("search"));String s=q.getParameter("status");s=s!=null&&Set.of("ACTIVE","INACTIVE").contains(s.toUpperCase())?s.toUpperCase():null;q.setAttribute("patientPage",service.listPatients(p,s));q.setAttribute("search",p.getSearchTerm());q.setAttribute("status",s==null?"":s);q.setAttribute("message",q.getParameter("message"));q.setAttribute("error",q.getParameter("error"));q.getRequestDispatcher("/WEB-INF/views/admin/patients/list.jsp").forward(q,r);}private int num(String s,int d){try{return Integer.parseInt(s);}catch(Exception e){return d;}}}
